           <em>
            <a href="https://email.mg2.substack.com/c/eJxFUcmu3CAQ_JrhhsXmefjAIZf8hsXSttHYgFgS-e_TM3OI1KpGlJoqqr3tsOd6m5JbJ29Y-13AJPjbTugdKhkN6hqD4U-h5awWEowKXM-axLZuFeCy8TS9DiBluDN622NOnwnGxEwOE4TjQTsVfpydn8uT-8ULvTkphHLM6q-uHSFC8mDgD9Q7JyCnOXov7SF_PcRvrA7-8HUkf0w-X3ghGP_BxgQClwgt2VIqvewLGo2d2m3LNVh3Au2Z4hEqtbTUvEFr6NKetBy5573aciCXEw34nxTwLRKNYAKLMy5nKeUkJuZmtYF1G1-09sFNsN3Dhud4KHbtYmrDtW796-2PVJNyd7nGtCP9OuwF54fAmFbs10ix3yukt7_wTbB_F_HJdN0hQcUFhdV2jF-pmXEh-MLlNzGMWOmZMSkVQeWQcSr9F_0HhmChiA" rel="">
